*** inet_addr.c#	Wed Feb  3 10:18:21 1999
--- inet_addr.c	Tue Feb 23 07:57:16 1999
***************
*** 115,123 ****
--- 115,127 ----
  		}
  		for (;;) {
  			if (isascii(c) && isdigit(c)) {
+ 				if (val >= (ULONG_MAX) / base)
+ 					return (0);
  				val = (val * base) + (c - '0');
  				c = *++cp;
  			} else if (base == 16 && isascii(c) && isxdigit(c)) {
+ 				if (val >= (ULONG_MAX) / base)
+ 					return (0);
  				val = (val << 4) |
  					(c + 10 - (islower(c) ? 'a' : 'A'));
  				c = *++cp;
***************
*** 157,175 ****
  		break;

  	case 2:				/* a.b -- 8.24 bits */
! 		if (val > 0xffffff)
  			return (0);
  		val |= parts[0] << 24;
  		break;

  	case 3:				/* a.b.c -- 8.8.16 bits */
! 		if (val > 0xffff)
  			return (0);
  		val |= (parts[0] << 24) | (parts[1] << 16);
  		break;

  	case 4:				/* a.b.c.d -- 8.8.8.8 bits */
! 		if (val > 0xff)
  			return (0);
  		val |= (parts[0] << 24) | (parts[1] << 16) | (parts[2] << 8);
  		break;
--- 161,180 ----
  		break;

  	case 2:				/* a.b -- 8.24 bits */
! 		if (parts[0] > 0xff || val > 0xffffff)
  			return (0);
  		val |= parts[0] << 24;
  		break;

  	case 3:				/* a.b.c -- 8.8.16 bits */
! 		if (parts[0] > 0xff || parts[1] || val > 0xffff)
  			return (0);
  		val |= (parts[0] << 24) | (parts[1] << 16);
  		break;

  	case 4:				/* a.b.c.d -- 8.8.8.8 bits */
! 		if (parts[0] > 0xff || parts[1] > 0xff || parts[2] > 0xff
! 		    || val > 0xff)
  			return (0);
  		val |= (parts[0] << 24) | (parts[1] << 16) | (parts[2] << 8);
  		break;
How-To-Repeat: 
call inet_addr("3493748787895789475489") and it won't return
INADDR_NONE.  Similarly, inet_addr("257.0.0.10") will return
0x0100000a... (on non-intel machines, anyway)
